from src.strategies.implemented_strategies import BaseImplementedStrategy
import pandas as pd
from src.utils.indicators import Indicators

class GeneratedStrategy20(BaseImplementedStrategy):
    def __init__(self):
        super().__init__("20", "经典-V 型反转（熊转牛）", trigger_timeframe="1min")
        self.history = {}

    def on_bar(self, kline):
        code = kline['code']
        if code not in self.history:
            self.history[code] = pd.DataFrame()
        self.history[code] = pd.concat([self.history[code], pd.DataFrame([kline])], ignore_index=True).tail(2000)
        df = self.history[code]
        if len(df) < 80:
            return None
        close = df['close']
        ma_fast = Indicators.MA(close, 12)
        ma_slow = Indicators.MA(close, 36)
        if len(ma_fast) < 2 or len(ma_slow) < 2:
            return None
        qty = int(self.positions.get(code, 0))
        c = float(kline['close'])
        stop_loss_pct = float(self._cfg("stop_loss_pct", 0.03))
        if qty <= 0 and float(ma_fast.iloc[-2]) <= float(ma_slow.iloc[-2]) and float(ma_fast.iloc[-1]) > float(ma_slow.iloc[-1]):
            buy_qty = int(self._qty())
            if buy_qty <= 0:
                return None
            return {
                'strategy_id': self.id,
                'code': code,
                'dt': kline['dt'],
                'direction': 'BUY',
                'price': c,
                'qty': buy_qty,
                'stop_loss': c * (1 - stop_loss_pct),
                'take_profit': None
            }
        if qty > 0 and float(ma_fast.iloc[-2]) >= float(ma_slow.iloc[-2]) and float(ma_fast.iloc[-1]) < float(ma_slow.iloc[-1]):
            return self.create_exit_signal(kline, qty, "MA Cross Exit")
        return None

from src.strategies.implemented_strategies import BaseImplementedStrategy
import pandas as pd
from src.utils.indicators import Indicators

class GeneratedStrategy21(BaseImplementedStrategy):
    def __init__(self):
        super().__init__("21", "TrendHold-Pro 趋势锁仓策略（增强合规版）", trigger_timeframe="1d")
        self.history = {}
        self.pending_sell = {}
        self.last_sell_bar_idx = {}
        self.entry_price = {}
        self.tp30_done = {}
        self.tp60_done = {}
        self.buy_streak = {}

    def _in_win(self, dt, s, e):
        x = pd.to_datetime(dt, errors="coerce")
        if pd.isna(x):
            return False
        hm = x.hour * 100 + x.minute
        return s <= hm <= e

    def _limit_ratio(self, code):
        c = str(code).split(".")[0]
        if c.startswith(("688", "689", "300", "301")):
            return 0.2
        return 0.1

    def on_bar(self, kline):
        code = str(kline.get("code", ""))
        self.history.setdefault(code, pd.DataFrame())
        self.history[code] = pd.concat([self.history[code], pd.DataFrame([kline])], ignore_index=True).tail(3000)
        df = self.history[code]
        if len(df) < 80:
            return None
        close = float(kline.get("close", 0) or 0)
        high = float(kline.get("high", 0) or 0)
        low = float(kline.get("low", 0) or 0)
        volume = float(kline.get("volume", kline.get("vol", 0)) or 0)
        if close <= 0 or high < low or volume <= 0:
            return None
        close_s = pd.to_numeric(df.get("close"), errors="coerce")
        vol_s = pd.to_numeric(df.get("volume", df.get("vol", 0)), errors="coerce").fillna(0)
        amt_s = pd.to_numeric(df.get("amount", close_s * vol_s), errors="coerce").fillna(0)
        ma20 = float(Indicators.MA(close_s, 20).iloc[-1])
        ma60 = float(Indicators.MA(close_s, 60).iloc[-1])
        atr14 = float(Indicators.ATR(df, window=14).iloc[-1])
        highest60 = float(pd.to_numeric(df.get("high"), errors="coerce").tail(60).max())
        vol20 = float(vol_s.rolling(20).mean().iloc[-1])
        amt20 = float(amt_s.rolling(20).mean().iloc[-1])
        ret20 = (close / float(close_s.iloc[-21]) - 1.0) if len(close_s) >= 21 and float(close_s.iloc[-21]) > 0 else 0.0
        prev_close = float(kline.get("prev_close", close_s.iloc[-2] if len(close_s) >= 2 else close))
        ratio = self._limit_ratio(code)
        limit_up = float(kline.get("limit_up", round(prev_close * (1 + ratio), 2)) or round(prev_close * (1 + ratio), 2))
        limit_down = float(kline.get("limit_down", round(prev_close * (1 - ratio), 2)) or round(prev_close * (1 - ratio), 2))
        qty = int(self.positions.get(code, 0))
        bar_idx = len(df)
        dt = kline.get("dt")

        if qty > 0 and self.pending_sell.get(code, False) and close > limit_down * 1.01:
            self.pending_sell[code] = False
            self.last_sell_bar_idx[code] = bar_idx
            sell_qty = int(qty // 100) * 100
            if sell_qty >= 100:
                return {"strategy_id": self.id, "code": code, "dt": dt, "direction": "SELL", "price": close * 0.998, "qty": sell_qty, "reason": "pending_sell_retry"}

        force_sell = (close < highest60 - 2.5 * atr14) or (close < ma60)
        if qty > 0 and force_sell:
            if close <= limit_down * 1.01:
                self.pending_sell[code] = True
                return None
            sell_qty = int(qty // 100) * 100
            if sell_qty >= 100:
                self.pending_sell[code] = False
                self.last_sell_bar_idx[code] = bar_idx
                return {"strategy_id": self.id, "code": code, "dt": dt, "direction": "SELL", "price": close * 0.998, "qty": sell_qty, "reason": "force_exit"}

        if qty > 0 and self._in_win(dt, 0, 2359):
            if close < ma20:
                sell_qty = int((qty * 0.5) // 100) * 100
                if sell_qty >= 100 and close > limit_down * 1.01:
                    return {"strategy_id": self.id, "code": code, "dt": dt, "direction": "SELL", "price": close * 0.998, "qty": sell_qty, "reason": "ma20_reduce"}
            ep = float(self.entry_price.get(code, 0) or 0)
            pnl = (close / ep - 1.0) if ep > 0 else 0.0
            if pnl >= 0.6 and not self.tp60_done.get(code, False):
                sell_qty = int((qty * 0.2) // 100) * 100
                if sell_qty >= 100 and close > limit_down * 1.01:
                    self.tp60_done[code] = True
                    return {"strategy_id": self.id, "code": code, "dt": dt, "direction": "SELL", "price": close * 0.998, "qty": sell_qty, "reason": "tp60"}
            if pnl >= 0.3 and not self.tp30_done.get(code, False):
                sell_qty = int((qty * 0.3) // 100) * 100
                if sell_qty >= 100 and close > limit_down * 1.01:
                    self.tp30_done[code] = True
                    return {"strategy_id": self.id, "code": code, "dt": dt, "direction": "SELL", "price": close * 0.998, "qty": sell_qty, "reason": "tp30"}

        buy_cond = (
            ma20 > ma60 and close > ma20 and ret20 > 0.07 and close < limit_up * 0.98
            and volume >= vol20 * 0.2 and amt20 > 30000000 and self._in_win(dt, 0, 2359)
        )
        self.buy_streak[code] = self.buy_streak.get(code, 0) + 1 if buy_cond else 0
        if qty <= 0 and self.buy_streak.get(code, 0) >= 2:
            if (bar_idx - int(self.last_sell_bar_idx.get(code, -10**9))) < 20:
                return None
            if close >= limit_up * 0.99:
                return None
            buy_qty = int(self._qty() // 100) * 100
            if buy_qty < 100:
                return None
            if buy_qty >= 100:
                self.entry_price[code] = close * 1.002
                self.tp30_done[code] = False
                self.tp60_done[code] = False
                return {"strategy_id": self.id, "code": code, "dt": dt, "direction": "BUY", "price": close * 1.002, "qty": buy_qty, "stop_loss": None, "take_profit": None}
        return None
